import{_ as e,a,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o,c as l,a2 as n}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"vi-VN/Other/blog.md","filePath":"vi-VN/Other/blog.md","lastUpdated":1781962217000}'),p={name:"vi-VN/Other/blog.md"};function c(r,t,d,h,g,u){return o(),l("div",null,[...t[0]||(t[0]=[n('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature thêm một blog page độc lập vào ImgBed site của bạn.</p><p>Sau khi bật, visitors có thể mở:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Blog homepage" loading="lazy"></p><p>Blog được điều chỉnh từ open-source project <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed rewrite và tích hợp nó với Vue để chạy như một phần của image hosting site.</p><h2 id="cau-hinh-o-đau" tabindex="-1">Cấu hình ở đâu <a class="header-anchor" href="#cau-hinh-o-đau" aria-label="Permalink to &quot;Cấu hình ở đâu&quot;">​</a></h2><p>Blog settings nằm tại:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>Bật <code>Enable</code>.</li><li>Chọn GitHub account dùng để lưu blog configuration.</li><li>Nhấn <code>Update Blog</code>.</li><li>Chờ success message.</li><li>Mở <code>https://your-domain.com/blog/</code> để xem blog.</li></ol><p>Khi dùng lần đầu, ImgBed sẽ chuẩn bị một private GitHub repository dưới account đã chọn:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Repository này lưu blog settings và article content.</p><h2 id="viet-posts" tabindex="-1">Viết Posts <a class="header-anchor" href="#viet-posts" aria-label="Permalink to &quot;Viết Posts&quot;">​</a></h2><p>Edit blog posts trong private GitHub repository:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typical workflow:</p><ol><li>Mở GitHub.</li><li>Vào private repository <code>imgbed-blog-config</code>.</li><li>Edit hoặc add post files.</li><li>Commit changes.</li><li>Quay lại ImgBed admin panel và nhấn <code>Update Blog</code>, hoặc nhấn logo ở góc trên bên trái blog homepage ba lần để trigger blog update.</li></ol><p><code>Update Blog</code> không overwrite content bạn đã viết. Nó chỉ initialize repository khi cần và refresh blog cache.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog hỗ trợ các tính năng blog phổ biến như post lists, categories, tags, archives, search, dark mode và language switching.</p><p>Nó cũng hỗ trợ comments và visit statistics.</p><p><img src="'+i+'" alt="Blog comments" loading="lazy"></p><p>Comments xuất hiện dưới posts. Visitors có thể submit avatar, nickname, email và comment content.</p><p>Visit statistics hiển thị post views và site visits, giúp bạn hiểu blog traffic.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog luôn được serve dưới <code>/blog/</code>.</p><p>Ví dụ, nếu ImgBed domain là:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>Blog URL sẽ là:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Sau khi blog bị disabled, visitors không thể access blog page nữa.</p>',34)])])}const k=s(p,[["render",c]]);export{v as __pageData,k as default};
